            aWandererD = aWandererD ^ (((RotL64(aIngress, 18U) + RotL64(aOrbiterB, 23U)) + aOrbiterI) + aPhaseCWandererUpdateSaltB[((aIndex + 23U)) & 31]);
            aWandererJ = aWandererJ + ((RotL64(aScatter, 57U) + RotL64(aOrbiterA, 37U)) + aOrbiterK);
