            //
            aCross = (RotL64(aFireLaneA[((S_BLOCK1 - aIndex + 8664U)) & S_BLOCK1], 37U) ^ RotL64(aFireLaneD[((S_BLOCK1 - aIndex + 6056U)) & S_BLOCK1], 24U));
            aCross ^= RotL64(aOperationLaneD[((S_BLOCK1 - aIndex + 7420U)) & S_BLOCK1], 57U);
            aCross = TwistMix64::DiffuseA(aCross);
